# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and attaches the results as additional
    headers before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment URLs specified, pass through
        return request
    
    # Extract enrichment URLs (support multiple comma-separated URLs in one header
    # or multiple header entries)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        urls = header_entry.get('value', '')
        for url in urls.split(','):
            stripped = url.strip()
            if stripped:
                enrich_urls.append(stripped)
    
    if not enrich_urls:
        return request
    
    # Validate URLs - only allow http and https schemes
    validated_urls = []
    for url in enrich_urls:
        if url.startswith('https://') or url.startswith('http://'):
            validated_urls.append(url)
    
    if not validated_urls:
        # Remove the enrichment header and pass through
        _cleanup_enrich_headers(headers)
        return request
    
    # Fetch data from each enrichment URL
    enrichment_results = []
    
    for idx, url in enumerate(validated_urls):
        result = _fetch_url(url)
        enrichment_results.append({
            'url': url,
            'index': idx,
            'status': result['status'],
            'data': result['data'],
            'error': result.get('error')
        })
    
    # Attach enrichment data as headers
    # Main enrichment result as JSON (base64-encoded to be header-safe)
    enrichment_payload = json.dumps(enrichment_results, default=str)
    encoded_payload = base64.b64encode(enrichment_payload.encode('utf-8')).decode('utf-8')
    
    # Add the enriched data header
    headers['x-enrichment-data'] = [{'key': 'X-Enrichment-Data', 'value': encoded_payload}]
    
    # Add individual enrichment results as separate headers for easy access
    for result in enrichment_results:
        header_name = f'x-enrichment-{result["index"]}-status'
        headers[header_name] = [{
            'key': f'X-Enrichment-{result["index"]}-Status',
            'value': str(result['status'])
        }]
        
        if result['status'] == 200 and result['data']:
            # Truncate individual data to stay within Lambda@Edge header size limits
            # Lambda@Edge has a limit of ~8KB per header value
            data_value = result['data'][:7000]
            data_encoded = base64.b64encode(data_value.encode('utf-8')).decode('utf-8')
            data_header_name = f'x-enrichment-{result["index"]}-data'
            headers[data_header_name] = [{
                'key': f'X-Enrichment-{result["index"]}-Data',
                'value': data_encoded
            }]
    
    # Add enrichment count header
    headers['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Clean up the original enrichment request header
    _cleanup_enrich_headers(headers)
    
    request['headers'] = headers
    return request


def _fetch_url(url, timeout=2):
    """
    Fetch data from a URL with timeout and error handling.
    
    Uses urllib (available in Lambda runtime) since requests library
    is not available by default in Lambda@Edge.
    
    Args:
        url: The URL to fetch
        timeout: Request timeout in seconds (keep low for edge performance)
    
    Returns:
        dict with 'status', 'data', and optionally 'error' keys
    """
    try:
        req = urllib.request.Request(
            url,
            headers={
                'User-Agent': 'Lambda-Edge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
            },
            method='GET'
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            status_code = response.getcode()
            # Read limited amount of data to prevent memory issues at edge
            # Lambda@Edge has memory constraints
            max_read_bytes = 16384  # 16KB max per URL response
            data = response.read(max_read_bytes).decode('utf-8', errors='replace')
            
            return {
                'status': status_code,
                'data': data
            }
    
    except urllib.error.HTTPError as e:
        return {
            'status': e.code,
            'data': None,
            'error': f'HTTP Error: {e.code} {e.reason}'
        }
    
    except urllib.error.URLError as e:
        return {
            'status': 0,
            'data': None,
            'error': f'URL Error: {str(e.reason)}'
        }
    
    except Exception as e:
        return {
            'status': 0,
            'data': None,
            'error': f'Error: {str(e)}'
        }


def _cleanup_enrich_headers(headers):
    """
    Remove the original enrichment URL headers to prevent
    them from being forwarded to the origin unnecessarily.
    """
    keys_to_remove = []
    for key in headers:
        if key.lower() == 'x-enrich-url':
            keys_to_remove.append(key)
    
    for key in keys_to_remove:
        del headers[key]